export default {
  id: 3,
  title: 'E-commerce: Spring Boot + React + Redis',
  description: 'Создайте интернет-магазин с каталогом товаров, корзиной, оформлением заказов, JWT-аутентификацией и Redis-кешированием. Бэкенд на Spring Boot, фронтенд на React, кеш на Redis, всё в Docker.',
  lessons: [
    {
      id: 301,
      title: 'Шаг 1: Spring Boot setup',
      type: 'practice',
      difficulty: 'easy',
      description: 'Создайте Spring Boot проект через Spring Initializr. Настройте зависимости, подключение к PostgreSQL и базовую конфигурацию приложения.',
      requirements: [
        'Создать проект через start.spring.io: Maven, Java 17, Spring Boot 3.x',
        'Зависимости: Spring Web, Spring Data JPA, PostgreSQL Driver, Spring Security, Spring Data Redis, Lombok, Validation',
        'Настроить application.properties: datasource, JPA, Redis',
        'Создать базовый ApplicationController с GET /api/health',
        'Добавить CORS конфигурацию для http://localhost:5173',
        'Убедиться что mvn spring-boot:run запускается без ошибок'
      ],
      expectedOutput: 'Приложение запускается на http://localhost:8080. GET /api/health возвращает {"status":"UP"}. В логах нет ошибок подключения к БД.',
      hint: 'application.properties: spring.datasource.url=jdbc:postgresql://localhost:5432/shopdb, spring.jpa.hibernate.ddl-auto=update, spring.data.redis.host=localhost, spring.data.redis.port=6379',
      solution: '// pom.xml (ключевые зависимости)\n<dependencies>\n    <dependency><groupId>org.springframework.boot</groupId>\n        <artifactId>spring-boot-starter-web</artifactId></dependency>\n    <dependency><groupId>org.springframework.boot</groupId>\n        <artifactId>spring-boot-starter-data-jpa</artifactId></dependency>\n    <dependency><groupId>org.springframework.boot</groupId>\n        <artifactId>spring-boot-starter-security</artifactId></dependency>\n    <dependency><groupId>org.springframework.boot</groupId>\n        <artifactId>spring-boot-starter-data-redis</artifactId></dependency>\n    <dependency><groupId>org.springframework.boot</groupId>\n        <artifactId>spring-boot-starter-validation</artifactId></dependency>\n    <dependency><groupId>org.postgresql</groupId>\n        <artifactId>postgresql</artifactId><scope>runtime</scope></dependency>\n    <dependency><groupId>org.projectlombok</groupId>\n        <artifactId>lombok</artifactId><optional>true</optional></dependency>\n    <dependency><groupId>io.jsonwebtoken</groupId>\n        <artifactId>jjwt-api</artifactId><version>0.11.5</version></dependency>\n</dependencies>\n\n\n# src/main/resources/application.properties\nspring.datasource.url=jdbc:postgresql://localhost:5432/shopdb\nspring.datasource.username=${DB_USERNAME:shopuser}\nspring.datasource.password=${DB_PASSWORD:shoppassword}\nspring.jpa.hibernate.ddl-auto=update\nspring.jpa.show-sql=false\nspring.data.redis.host=${REDIS_HOST:localhost}\nspring.data.redis.port=${REDIS_PORT:6379}\nserver.port=8080\napp.jwt.secret=${JWT_SECRET:mySecretKey12345678901234567890}\napp.jwt.expiration=86400000\n\n\n// src/main/java/com/shop/config/CorsConfig.java\n@Configuration\npublic class CorsConfig {\n    @Bean\n    public CorsConfigurationSource corsConfigurationSource() {\n        CorsConfiguration config = new CorsConfiguration();\n        config.setAllowedOrigins(List.of("http://localhost:5173"));\n        config.setAllowedMethods(List.of("GET","POST","PUT","DELETE","OPTIONS"));\n        config.setAllowedHeaders(List.of("*"));\n        config.setAllowCredentials(true);\n        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();\n        source.registerCorsConfiguration("/api/**", config);\n        return source;\n    }\n}\n\n\n// src/main/java/com/shop/controller/HealthController.java\n@RestController\n@RequestMapping("/api")\npublic class HealthController {\n    @GetMapping("/health")\n    public Map<String, String> health() {\n        return Map.of("status", "UP");\n    }\n}',
      explanation: 'Spring Boot auto-configuration настраивает большую часть инфраструктуры автоматически — достаточно добавить зависимость в pom.xml. ${ENV_VAR:defaultValue} в application.properties позволяет переопределять настройки через переменные окружения без изменения кода. Lombok генерирует boilerplate (getters, setters, constructors) в compile-time.'
    },
    {
      id: 302,
      title: 'Шаг 2: Модели (Product, Category, User, Order, OrderItem)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создайте JPA-сущности для всех объектов магазина с правильными связями и ограничениями.',
      requirements: [
        'Category: id, name, slug, description',
        'Product: id, name, slug, description, price (BigDecimal), stock, imageUrl, category (ManyToOne)',
        'User: id, email (unique), password, firstName, lastName, role (CUSTOMER/ADMIN)',
        'Order: id, user (ManyToOne), status (PENDING/CONFIRMED/SHIPPED/DELIVERED/CANCELLED), totalAmount, createdAt',
        'OrderItem: id, order (ManyToOne), product (ManyToOne), quantity, priceAtTime',
        'Использовать @Enumerated(EnumType.STRING) для статусов',
        'Lombok: @Entity, @Data, @NoArgsConstructor, @AllArgsConstructor, @Builder'
      ],
      expectedOutput: 'spring.jpa.hibernate.ddl-auto=update создаёт все таблицы при старте. В логах JPA видны CREATE TABLE запросы. Таблицы появляются в PostgreSQL.',
      hint: '@Column(precision=10, scale=2) для BigDecimal цены. @ManyToOne(fetch=FetchType.LAZY) для производительности. @CreationTimestamp для createdAt. @JsonIgnoreProperties("orders") на User чтобы избежать circular reference.',
      solution: '// src/main/java/com/shop/entity/Category.java\n@Entity @Table(name = "categories")\n@Data @NoArgsConstructor @AllArgsConstructor @Builder\npublic class Category {\n    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)\n    private Long id;\n    @Column(nullable = false, unique = true)\n    private String name;\n    @Column(unique = true)\n    private String slug;\n    private String description;\n}\n\n\n// src/main/java/com/shop/entity/Product.java\n@Entity @Table(name = "products")\n@Data @NoArgsConstructor @AllArgsConstructor @Builder\npublic class Product {\n    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)\n    private Long id;\n    @Column(nullable = false)\n    private String name;\n    @Column(unique = true)\n    private String slug;\n    @Column(columnDefinition = "TEXT")\n    private String description;\n    @Column(nullable = false, precision = 10, scale = 2)\n    private BigDecimal price;\n    @Column(nullable = false)\n    private Integer stock;\n    private String imageUrl;\n    @ManyToOne(fetch = FetchType.LAZY)\n    @JoinColumn(name = "category_id")\n    @JsonIgnoreProperties({"products","hibernateLazyInitializer"})\n    private Category category;\n}\n\n\n// src/main/java/com/shop/entity/AppUser.java\n@Entity @Table(name = "users")\n@Data @NoArgsConstructor @AllArgsConstructor @Builder\npublic class AppUser {\n    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)\n    private Long id;\n    @Column(nullable = false, unique = true)\n    private String email;\n    @Column(nullable = false)\n    @JsonIgnore\n    private String password;\n    private String firstName;\n    private String lastName;\n    @Enumerated(EnumType.STRING)\n    @Column(nullable = false)\n    private Role role = Role.CUSTOMER;\n\n    public enum Role { CUSTOMER, ADMIN }\n}\n\n\n// src/main/java/com/shop/entity/Order.java\n@Entity @Table(name = "orders")\n@Data @NoArgsConstructor @AllArgsConstructor @Builder\npublic class Order {\n    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)\n    private Long id;\n    @ManyToOne(fetch = FetchType.LAZY)\n    @JoinColumn(name = "user_id", nullable = false)\n    @JsonIgnoreProperties({"hibernateLazyInitializer"})\n    private AppUser user;\n    @Enumerated(EnumType.STRING)\n    private OrderStatus status = OrderStatus.PENDING;\n    @Column(nullable = false, precision = 10, scale = 2)\n    private BigDecimal totalAmount;\n    @OneToMany(mappedBy = "order", cascade = CascadeType.ALL, fetch = FetchType.EAGER)\n    private List<OrderItem> items = new ArrayList<>();\n    @CreationTimestamp\n    private LocalDateTime createdAt;\n\n    public enum OrderStatus { PENDING, CONFIRMED, SHIPPED, DELIVERED, CANCELLED }\n}\n\n\n// src/main/java/com/shop/entity/OrderItem.java\n@Entity @Table(name = "order_items")\n@Data @NoArgsConstructor @AllArgsConstructor @Builder\npublic class OrderItem {\n    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)\n    private Long id;\n    @ManyToOne(fetch = FetchType.LAZY)\n    @JoinColumn(name = "order_id")\n    @JsonIgnore\n    private Order order;\n    @ManyToOne(fetch = FetchType.LAZY)\n    @JoinColumn(name = "product_id")\n    private Product product;\n    private Integer quantity;\n    @Column(precision = 10, scale = 2)\n    private BigDecimal priceAtTime;\n}',
      explanation: 'BigDecimal вместо double для денег — критично, double теряет точность при десятичных вычислениях ($0.1 + $0.2 != $0.3). FetchType.LAZY загружает связанные объекты только при обращении — производительнее, чем EAGER. @JsonIgnore на password предотвращает утечку пароля в API-ответах. priceAtTime в OrderItem фиксирует цену на момент покупки, даже если цена товара изменится.'
    },
    {
      id: 303,
      title: 'Шаг 3: REST API (ProductController, OrderController)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создайте REST контроллеры и слой сервисов для управления товарами и заказами. Реализуйте паттерн Repository + Service + Controller.',
      requirements: [
        'ProductRepository: extends JpaRepository, метод findByCategory и findBySlug',
        'ProductService: getAll, getById, getBySlug, create, update, delete',
        'ProductController: GET /api/products (с фильтром category), GET /api/products/{id}, POST/PUT/DELETE (только ADMIN)',
        'OrderRepository: findByUserOrderByCreatedAtDesc',
        'OrderService: createOrder (уменьшает stock), getMyOrders, cancelOrder',
        'OrderController: POST /api/orders, GET /api/orders/my, PUT /api/orders/{id}/cancel',
        'DTO классы (ProductDTO, OrderDTO) для запросов и ответов'
      ],
      expectedOutput: 'GET /api/products возвращает список товаров. POST /api/products (с JWT токеном ADMIN) создаёт товар. POST /api/orders создаёт заказ и уменьшает stock товаров.',
      hint: 'В OrderService.createOrder(): проверить наличие товара (stock >= quantity), создать Order и OrderItems, уменьшить stock, сохранить. Используйте @Transactional для атомарности операции.',
      solution: '// src/main/java/com/shop/repository/ProductRepository.java\n@Repository\npublic interface ProductRepository extends JpaRepository<Product, Long> {\n    List<Product> findByCategoryId(Long categoryId);\n    Optional<Product> findBySlug(String slug);\n    Page<Product> findByNameContainingIgnoreCase(String name, Pageable pageable);\n    Page<Product> findByCategoryIdAndNameContainingIgnoreCase(\n        Long categoryId, String name, Pageable pageable);\n}\n\n\n// src/main/java/com/shop/service/ProductService.java\n@Service @RequiredArgsConstructor\npublic class ProductService {\n    private final ProductRepository productRepository;\n    private final CategoryRepository categoryRepository;\n\n    public Page<Product> getProducts(Long categoryId, String search, Pageable pageable) {\n        if (categoryId != null && search != null) {\n            return productRepository.findByCategoryIdAndNameContainingIgnoreCase(\n                categoryId, search, pageable);\n        } else if (categoryId != null) {\n            return productRepository.findByCategoryId(categoryId, pageable);\n        } else if (search != null) {\n            return productRepository.findByNameContainingIgnoreCase(search, pageable);\n        }\n        return productRepository.findAll(pageable);\n    }\n\n    public Product getByIdOrThrow(Long id) {\n        return productRepository.findById(id)\n            .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Товар не найден"));\n    }\n\n    @Transactional\n    public Product create(ProductDTO dto) {\n        Category category = categoryRepository.findById(dto.getCategoryId())\n            .orElseThrow(() -> new ResponseStatusException(HttpStatus.BAD_REQUEST, "Категория не найдена"));\n        Product product = Product.builder()\n            .name(dto.getName()).description(dto.getDescription())\n            .price(dto.getPrice()).stock(dto.getStock())\n            .imageUrl(dto.getImageUrl()).category(category)\n            .slug(generateSlug(dto.getName())).build();\n        return productRepository.save(product);\n    }\n}\n\n\n// src/main/java/com/shop/controller/ProductController.java\n@RestController\n@RequestMapping("/api/products")\n@RequiredArgsConstructor\npublic class ProductController {\n    private final ProductService productService;\n\n    @GetMapping\n    public Page<Product> getProducts(\n            @RequestParam(required = false) Long categoryId,\n            @RequestParam(required = false) String search,\n            @RequestParam(defaultValue = "0") int page,\n            @RequestParam(defaultValue = "12") int size) {\n        return productService.getProducts(categoryId, search,\n            PageRequest.of(page, size, Sort.by("id")));\n    }\n\n    @GetMapping("/{id}")\n    public Product getProduct(@PathVariable Long id) {\n        return productService.getByIdOrThrow(id);\n    }\n\n    @PostMapping\n    @PreAuthorize("hasRole(\'ADMIN\')")\n    @ResponseStatus(HttpStatus.CREATED)\n    public Product createProduct(@Valid @RequestBody ProductDTO dto) {\n        return productService.create(dto);\n    }\n\n    @DeleteMapping("/{id}")\n    @PreAuthorize("hasRole(\'ADMIN\')")\n    @ResponseStatus(HttpStatus.NO_CONTENT)\n    public void deleteProduct(@PathVariable Long id) {\n        productService.delete(id);\n    }\n}\n\n\n// src/main/java/com/shop/service/OrderService.java\n@Service @RequiredArgsConstructor\npublic class OrderService {\n    private final OrderRepository orderRepository;\n    private final ProductRepository productRepository;\n\n    @Transactional\n    public Order createOrder(AppUser user, List<OrderItemRequest> items) {\n        List<OrderItem> orderItems = new ArrayList<>();\n        BigDecimal total = BigDecimal.ZERO;\n\n        for (OrderItemRequest item : items) {\n            Product product = productRepository.findById(item.getProductId())\n                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Товар не найден"));\n            if (product.getStock() < item.getQuantity()) {\n                throw new ResponseStatusException(HttpStatus.BAD_REQUEST,\n                    "Недостаточно товара: " + product.getName());\n            }\n            product.setStock(product.getStock() - item.getQuantity());\n            productRepository.save(product);\n\n            OrderItem orderItem = OrderItem.builder()\n                .product(product).quantity(item.getQuantity())\n                .priceAtTime(product.getPrice()).build();\n            orderItems.add(orderItem);\n            total = total.add(product.getPrice().multiply(new BigDecimal(item.getQuantity())));\n        }\n\n        Order order = Order.builder()\n            .user(user).items(orderItems).totalAmount(total)\n            .status(Order.OrderStatus.PENDING).build();\n        orderItems.forEach(oi -> oi.setOrder(order));\n        return orderRepository.save(order);\n    }\n}',
      explanation: '@Transactional на createOrder гарантирует: либо все операции (уменьшение stock, создание заказа) выполняются успешно, либо при ошибке всё откатывается. Паттерн Repository+Service+Controller разделяет ответственности: Repository работает с БД, Service содержит бизнес-логику, Controller обрабатывает HTTP. Page<Product> из Spring Data даёт пагинацию без лишнего кода.'
    },
    {
      id: 304,
      title: 'Шаг 4: Spring Security + JWT',
      type: 'practice',
      difficulty: 'hard',
      description: 'Настройте Spring Security с JWT-аутентификацией. Создайте JwtUtil, JwtFilter, SecurityConfig и эндпоинты для регистрации и входа.',
      requirements: [
        'JwtUtil: generateToken(UserDetails), validateToken, getUsernameFromToken',
        'JwtAuthenticationFilter: extends OncePerRequestFilter, читает Bearer токен из заголовка',
        'SecurityConfig: отключить CSRF, настроить stateless session, whitelist /api/auth/**',
        'UserDetailsService: загружает пользователя по email из БД',
        'POST /api/auth/register: регистрация, возвращает JWT',
        'POST /api/auth/login: логин, возвращает JWT',
        '@PreAuthorize("hasRole(\'ADMIN\')") для административных эндпоинтов'
      ],
      expectedOutput: 'POST /api/auth/login с {email, password} возвращает {token, user}. GET /api/products работает без токена. POST /api/products без токена возвращает 403.',
      hint: 'Зависимости JWT: io.jsonwebtoken:jjwt-api:0.11.5, jjwt-impl, jjwt-jackson. Jwts.builder().setSubject(username).setExpiration(new Date(System.currentTimeMillis() + expiration)).signWith(getSignKey(), SignatureAlgorithm.HS256).compact()',
      solution: '// src/main/java/com/shop/security/JwtUtil.java\n@Component\npublic class JwtUtil {\n    @Value("${app.jwt.secret}")\n    private String secret;\n    @Value("${app.jwt.expiration}")\n    private long expiration;\n\n    private Key getSignKey() {\n        byte[] keyBytes = Decoders.BASE64.decode(secret);\n        return Keys.hmacShaKeyFor(keyBytes);\n    }\n\n    public String generateToken(UserDetails userDetails) {\n        Map<String, Object> claims = new HashMap<>();\n        return Jwts.builder()\n            .setClaims(claims)\n            .setSubject(userDetails.getUsername())\n            .setIssuedAt(new Date())\n            .setExpiration(new Date(System.currentTimeMillis() + expiration))\n            .signWith(getSignKey(), SignatureAlgorithm.HS256)\n            .compact();\n    }\n\n    public String getUsernameFromToken(String token) {\n        return Jwts.parserBuilder().setSigningKey(getSignKey()).build()\n            .parseClaimsJws(token).getBody().getSubject();\n    }\n\n    public boolean validateToken(String token, UserDetails userDetails) {\n        final String username = getUsernameFromToken(token);\n        return username.equals(userDetails.getUsername()) && !isTokenExpired(token);\n    }\n\n    private boolean isTokenExpired(String token) {\n        Date expiry = Jwts.parserBuilder().setSigningKey(getSignKey()).build()\n            .parseClaimsJws(token).getBody().getExpiration();\n        return expiry.before(new Date());\n    }\n}\n\n\n// src/main/java/com/shop/security/JwtAuthFilter.java\n@Component @RequiredArgsConstructor\npublic class JwtAuthFilter extends OncePerRequestFilter {\n    private final JwtUtil jwtUtil;\n    private final UserDetailsService userDetailsService;\n\n    @Override\n    protected void doFilterInternal(HttpServletRequest request,\n            HttpServletResponse response, FilterChain filterChain)\n            throws ServletException, IOException {\n        final String authHeader = request.getHeader("Authorization");\n        if (authHeader == null || !authHeader.startsWith("Bearer ")) {\n            filterChain.doFilter(request, response);\n            return;\n        }\n        String token = authHeader.substring(7);\n        String username = jwtUtil.getUsernameFromToken(token);\n        if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {\n            UserDetails userDetails = userDetailsService.loadUserByUsername(username);\n            if (jwtUtil.validateToken(token, userDetails)) {\n                UsernamePasswordAuthenticationToken authToken =\n                    new UsernamePasswordAuthenticationToken(userDetails, null, userDetails.getAuthorities());\n                authToken.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));\n                SecurityContextHolder.getContext().setAuthentication(authToken);\n            }\n        }\n        filterChain.doFilter(request, response);\n    }\n}\n\n\n// src/main/java/com/shop/config/SecurityConfig.java\n@Configuration @EnableWebSecurity @EnableMethodSecurity\n@RequiredArgsConstructor\npublic class SecurityConfig {\n    private final JwtAuthFilter jwtAuthFilter;\n    private final UserDetailsService userDetailsService;\n\n    @Bean\n    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {\n        http\n            .csrf(AbstractHttpConfigurer::disable)\n            .cors(cors -> cors.configurationSource(corsConfigurationSource()))\n            .sessionManagement(sm -> sm.sessionCreationPolicy(SessionCreationPolicy.STATELESS))\n            .authorizeHttpRequests(auth -> auth\n                .requestMatchers("/api/auth/**").permitAll()\n                .requestMatchers(HttpMethod.GET, "/api/products/**", "/api/categories/**").permitAll()\n                .anyRequest().authenticated()\n            )\n            .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class);\n        return http.build();\n    }\n\n    @Bean\n    public PasswordEncoder passwordEncoder() {\n        return new BCryptPasswordEncoder();\n    }\n}',
      explanation: 'OncePerRequestFilter гарантирует что фильтр выполнится ровно один раз на запрос. SecurityContextHolder.getContext().setAuthentication() регистрирует пользователя как аутентифицированного на время обработки запроса. @EnableMethodSecurity включает @PreAuthorize аннотации на уровне методов. BCrypt хеширует пароли с автоматической солью — безопасно даже при утечке БД.'
    },
    {
      id: 305,
      title: 'Шаг 5: React: каталог товаров',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создайте страницу каталога товаров с карточками, фильтрацией по категориям и поиском. Настройте Vite-проект с axios и React Router.',
      requirements: [
        'Установить: react-router-dom, axios',
        'Страница Catalog: сетка карточек товаров (3-4 в ряд)',
        'ProductCard: изображение, название, цена, кнопка "В корзину"',
        'Сайдбар с фильтрацией по категории',
        'Поиск с debounce 300ms',
        'Пагинация (Spring возвращает Page объект)',
        'Адаптивный дизайн: на мобильных — 1-2 карточки в ряд'
      ],
      expectedOutput: 'Страница /catalog показывает сетку товаров. Клик на категорию фильтрует список. Поиск работает с задержкой. Пагинация позволяет навигировать по страницам.',
      hint: 'Spring Page ответ: { content: [...], totalPages, totalElements, number }. Для сетки: display: grid; grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)). Кнопка "В корзину" пока только добавляет в localStorage.',
      solution: '// src/pages/Catalog.jsx\nimport { useState, useEffect } from "react";\nimport { useSearchParams } from "react-router-dom";\nimport api from "../api/axios";\nimport ProductCard from "../components/ProductCard";\nimport CategorySidebar from "../components/CategorySidebar";\nimport { useDebounce } from "../hooks/useDebounce";\nimport styles from "./Catalog.module.css";\n\nexport default function Catalog() {\n  const [searchParams, setSearchParams] = useSearchParams();\n  const [products, setProducts] = useState([]);\n  const [categories, setCategories] = useState([]);\n  const [totalPages, setTotalPages] = useState(0);\n  const [loading, setLoading] = useState(true);\n\n  const page = parseInt(searchParams.get("page") || "0");\n  const categoryId = searchParams.get("category");\n  const search = searchParams.get("search") || "";\n  const debouncedSearch = useDebounce(search);\n\n  useEffect(() => {\n    api.get("/categories").then((r) => setCategories(r.data));\n  }, []);\n\n  useEffect(() => {\n    setLoading(true);\n    const params = { page, size: 12 };\n    if (categoryId) params.categoryId = categoryId;\n    if (debouncedSearch) params.search = debouncedSearch;\n    api.get("/products", { params }).then((r) => {\n      setProducts(r.data.content);\n      setTotalPages(r.data.totalPages);\n      setLoading(false);\n    });\n  }, [page, categoryId, debouncedSearch]);\n\n  return (\n    <div className={styles.layout}>\n      <CategorySidebar\n        categories={categories}\n        selected={categoryId}\n        onSelect={(id) => setSearchParams({ category: id, page: 0 })}\n      />\n      <main className={styles.main}>\n        <input\n          className={styles.searchInput}\n          placeholder="Поиск товаров..."\n          value={search}\n          onChange={(e) => setSearchParams({ search: e.target.value, page: 0, category: categoryId || "" })}\n        />\n        {loading ? <div>Загрузка...</div> : (\n          <>\n            <div className={styles.grid}>\n              {products.map((p) => <ProductCard key={p.id} product={p} />)}\n            </div>\n            <div className={styles.pagination}>\n              {Array.from({ length: totalPages }, (_, i) => (\n                <button\n                  key={i}\n                  className={i === page ? styles.active : ""}\n                  onClick={() => setSearchParams({ page: i, category: categoryId || "", search })}\n                >\n                  {i + 1}\n                </button>\n              ))}\n            </div>\n          </>\n        )}\n      </main>\n    </div>\n  );\n}\n\n\n// src/components/ProductCard.jsx\nimport { useCart } from "../context/CartContext";\nimport styles from "./ProductCard.module.css";\n\nexport default function ProductCard({ product }) {\n  const { addToCart } = useCart();\n\n  return (\n    <div className={styles.card}>\n      <img src={product.imageUrl || "/placeholder.jpg"} alt={product.name} />\n      <div className={styles.body}>\n        <h3>{product.name}</h3>\n        <p className={styles.price}>{product.price.toLocaleString("ru-RU")} ₽</p>\n        <p className={styles.stock}>\n          {product.stock > 0 ? `В наличии: ${product.stock}` : "Нет в наличии"}\n        </p>\n        <button\n          onClick={() => addToCart(product)}\n          disabled={product.stock === 0}\n          className={styles.addBtn}\n        >\n          В корзину\n        </button>\n      </div>\n    </div>\n  );\n}\n\n\n/* src/components/ProductCard.module.css */\n.card {\n  border: 1px solid #e5e7eb;\n  border-radius: 12px;\n  overflow: hidden;\n  transition: transform 0.2s, box-shadow 0.2s;\n  background: white;\n}\n.card:hover {\n  transform: translateY(-4px);\n  box-shadow: 0 10px 25px rgba(0,0,0,0.1);\n}\n.card img { width: 100%; height: 200px; object-fit: cover; }\n.body { padding: 1rem; }\n.price { font-size: 1.25rem; font-weight: bold; color: #1d4ed8; }\n.addBtn {\n  width: 100%; padding: 0.5rem;\n  background: #2563eb; color: white; border: none;\n  border-radius: 8px; cursor: pointer; margin-top: 0.5rem;\n}\n.addBtn:disabled { background: #9ca3af; cursor: not-allowed; }',
      explanation: 'CSS Grid с auto-fill и minmax автоматически выбирает количество колонок в зависимости от ширины экрана — responsive без media queries. product.stock === 0 блокирует кнопку на уровне UI. Пагинация Spring (page от 0) отличается от Django (page от 1) — важно учитывать при построении UI.'
    },
    {
      id: 306,
      title: 'Шаг 6: React: корзина (localStorage)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуйте корзину покупок с использованием React Context и localStorage для сохранения между сессиями. Создайте страницу корзины с изменением количества товаров.',
      requirements: [
        'CartContext: items, addToCart, removeFromCart, updateQuantity, clearCart, totalPrice, totalItems',
        'Сохранять корзину в localStorage при каждом изменении',
        'Восстанавливать корзину из localStorage при загрузке приложения',
        'Страница /cart: список товаров, количество, сумма',
        'Изменение количества с кнопками +/-',
        'Кнопка "Удалить" для каждого товара',
        'Счётчик на иконке корзины в навбаре'
      ],
      expectedOutput: 'Товары добавляются в корзину, количество отображается на иконке. После перезагрузки страницы корзина сохраняется. На странице корзины показывается итоговая сумма.',
      hint: 'useEffect(() => { localStorage.setItem("cart", JSON.stringify(items)) }, [items]) для сохранения. Инициализация: useState(() => { const saved = localStorage.getItem("cart"); return saved ? JSON.parse(saved) : []; })',
      solution: '// src/context/CartContext.jsx\nimport { createContext, useContext, useState, useEffect } from "react";\n\nconst CartContext = createContext(null);\n\nexport function CartProvider({ children }) {\n  const [items, setItems] = useState(() => {\n    try {\n      const saved = localStorage.getItem("cart");\n      return saved ? JSON.parse(saved) : [];\n    } catch {\n      return [];\n    }\n  });\n\n  useEffect(() => {\n    localStorage.setItem("cart", JSON.stringify(items));\n  }, [items]);\n\n  const addToCart = (product) => {\n    setItems((prev) => {\n      const existing = prev.find((i) => i.id === product.id);\n      if (existing) {\n        return prev.map((i) =>\n          i.id === product.id\n            ? { ...i, quantity: Math.min(i.quantity + 1, product.stock) }\n            : i\n        );\n      }\n      return [...prev, { ...product, quantity: 1 }];\n    });\n  };\n\n  const removeFromCart = (productId) =>\n    setItems((prev) => prev.filter((i) => i.id !== productId));\n\n  const updateQuantity = (productId, quantity) => {\n    if (quantity < 1) { removeFromCart(productId); return; }\n    setItems((prev) =>\n      prev.map((i) => (i.id === productId ? { ...i, quantity } : i))\n    );\n  };\n\n  const clearCart = () => setItems([]);\n\n  const totalItems = items.reduce((sum, i) => sum + i.quantity, 0);\n  const totalPrice = items.reduce((sum, i) => sum + i.price * i.quantity, 0);\n\n  return (\n    <CartContext.Provider value={{ items, addToCart, removeFromCart, updateQuantity, clearCart, totalItems, totalPrice }}>\n      {children}\n    </CartContext.Provider>\n  );\n}\n\nexport const useCart = () => useContext(CartContext);\n\n\n// src/pages/Cart.jsx\nimport { Link, useNavigate } from "react-router-dom";\nimport { useCart } from "../context/CartContext";\nimport styles from "./Cart.module.css";\n\nexport default function Cart() {\n  const { items, removeFromCart, updateQuantity, totalPrice, clearCart } = useCart();\n  const navigate = useNavigate();\n\n  if (items.length === 0) {\n    return (\n      <div className={styles.empty}>\n        <h2>Корзина пуста</h2>\n        <Link to="/catalog">Перейти к покупкам</Link>\n      </div>\n    );\n  }\n\n  return (\n    <div className={styles.container}>\n      <h1>Корзина</h1>\n      <div className={styles.items}>\n        {items.map((item) => (\n          <div key={item.id} className={styles.item}>\n            <img src={item.imageUrl || "/placeholder.jpg"} alt={item.name} />\n            <div className={styles.info}>\n              <h3>{item.name}</h3>\n              <p>{item.price.toLocaleString("ru-RU")} ₽</p>\n            </div>\n            <div className={styles.quantity}>\n              <button onClick={() => updateQuantity(item.id, item.quantity - 1)}>-</button>\n              <span>{item.quantity}</span>\n              <button onClick={() => updateQuantity(item.id, item.quantity + 1)}>+</button>\n            </div>\n            <p className={styles.subtotal}>\n              {(item.price * item.quantity).toLocaleString("ru-RU")} ₽\n            </p>\n            <button onClick={() => removeFromCart(item.id)} className={styles.removeBtn}>\n              ✕\n            </button>\n          </div>\n        ))}\n      </div>\n      <div className={styles.total}>\n        <h2>Итого: {totalPrice.toLocaleString("ru-RU")} ₽</h2>\n        <button onClick={() => navigate("/checkout")} className={styles.checkoutBtn}>\n          Оформить заказ\n        </button>\n      </div>\n    </div>\n  );\n}',
      explanation: 'Lazy initial state в useState(() => JSON.parse(...)) — функция выполняется только один раз при монтировании, не при каждом ре-рендере. Math.min(quantity + 1, product.stock) предотвращает добавление больше чем есть в наличии. toLocaleString("ru-RU") форматирует число как "1 500 ₽" по российским стандартам.'
    },
    {
      id: 307,
      title: 'Шаг 7: React: оформление заказа',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создайте страницу оформления заказа: форма с адресом доставки, сводка заказа, отправка на бэкенд и страница подтверждения.',
      requirements: [
        'Страница /checkout: только для авторизованных (PrivateRoute)',
        'Форма: имя, email, адрес доставки, телефон',
        'Сводка заказа справа: список товаров из корзины и итоговая сумма',
        'POST /api/orders с телом { items: [{productId, quantity}] }',
        'После успешного заказа: очистить корзину, перейти на /order-success',
        'Страница /order-success с номером заказа и кнопкой "Мои заказы"',
        'Обработка ошибки "Недостаточно товара" от сервера'
      ],
      expectedOutput: 'Страница оформления заказа доступна только залогиненным пользователям. После отправки формы заказ создаётся в БД, корзина очищается, отображается страница успеха с номером заказа.',
      hint: 'После успешного POST: clearCart(), navigate("/order-success", { state: { orderId: res.data.id } }). На странице успеха: const { state } = useLocation(); const orderId = state?.orderId.',
      solution: '// src/pages/Checkout.jsx\nimport { useState } from "react";\nimport { useNavigate } from "react-router-dom";\nimport { useCart } from "../context/CartContext";\nimport { useAuth } from "../context/AuthContext";\nimport api from "../api/axios";\nimport styles from "./Checkout.module.css";\n\nexport default function Checkout() {\n  const { items, totalPrice, clearCart } = useCart();\n  const { user } = useAuth();\n  const navigate = useNavigate();\n  const [form, setForm] = useState({\n    name: user ? `${user.firstName} ${user.lastName}` : "",\n    email: user?.email || "",\n    address: "",\n    phone: "",\n  });\n  const [error, setError] = useState(null);\n  const [loading, setLoading] = useState(false);\n\n  const handleSubmit = async (e) => {\n    e.preventDefault();\n    setLoading(true);\n    setError(null);\n    try {\n      const orderData = {\n        items: items.map((i) => ({ productId: i.id, quantity: i.quantity })),\n        shippingAddress: form.address,\n        phone: form.phone,\n      };\n      const res = await api.post("/orders", orderData);\n      clearCart();\n      navigate("/order-success", { state: { orderId: res.data.id } });\n    } catch (err) {\n      setError(err.response?.data?.message || "Ошибка при оформлении заказа");\n      setLoading(false);\n    }\n  };\n\n  return (\n    <div className={styles.container}>\n      <div className={styles.formSection}>\n        <h2>Данные доставки</h2>\n        {error && <div className={styles.error}>{error}</div>}\n        <form onSubmit={handleSubmit}>\n          <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })}\n            placeholder="Ваше имя" required />\n          <input value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })}\n            placeholder="Email" type="email" required />\n          <input value={form.phone} onChange={(e) => setForm({ ...form, phone: e.target.value })}\n            placeholder="Телефон" required />\n          <textarea value={form.address} onChange={(e) => setForm({ ...form, address: e.target.value })}\n            placeholder="Адрес доставки" rows={3} required />\n          <button type="submit" disabled={loading}>\n            {loading ? "Оформляем..." : "Подтвердить заказ"}\n          </button>\n        </form>\n      </div>\n      <div className={styles.summary}>\n        <h2>Ваш заказ</h2>\n        {items.map((item) => (\n          <div key={item.id} className={styles.summaryItem}>\n            <span>{item.name} x{item.quantity}</span>\n            <span>{(item.price * item.quantity).toLocaleString("ru-RU")} ₽</span>\n          </div>\n        ))}\n        <hr />\n        <div className={styles.total}>\n          <strong>Итого: {totalPrice.toLocaleString("ru-RU")} ₽</strong>\n        </div>\n      </div>\n    </div>\n  );\n}\n\n\n// src/pages/OrderSuccess.jsx\nimport { useLocation, Link } from "react-router-dom";\n\nexport default function OrderSuccess() {\n  const { state } = useLocation();\n  return (\n    <div className="success-page">\n      <h1>Заказ оформлен!</h1>\n      <p>Номер вашего заказа: <strong>#{state?.orderId}</strong></p>\n      <Link to="/orders">Мои заказы</Link>\n    </div>\n  );\n}',
      explanation: 'Передача данных между страницами через navigate state (не URL параметры) — orderId не виден в URL, не кешируется, исчезает при refresh (что правильно для страницы успеха). err.response?.data?.message извлекает сообщение об ошибке из ответа Spring (ResponseStatusException message). disabled={loading} предотвращает двойную отправку формы.'
    },
    {
      id: 308,
      title: 'Шаг 8: Redis кеширование (товары, сессии)',
      type: 'practice',
      difficulty: 'hard',
      description: 'Добавьте Redis кеширование для часто запрашиваемых данных: каталог товаров и категорий. Настройте Spring Cache с Redis как backend.',
      requirements: [
        'Включить @EnableCaching в главном классе приложения',
        'Настроить RedisCacheConfiguration: TTL 10 минут, JSON сериализация',
        '@Cacheable("products") на ProductService.getProducts()',
        '@Cacheable("categories") на CategoryService.getAll()',
        '@CacheEvict на методах создания/обновления/удаления товаров',
        'Подключить RedisTemplate для ручного управления кешем (опционально)',
        'Добавить логирование: "Cache hit" / "Cache miss"'
      ],
      expectedOutput: 'Первый запрос GET /api/products обращается к БД (видно в логах SQL). Повторный запрос возвращается мгновенно из Redis без SQL-запроса. После создания нового товара кеш инвалидируется.',
      hint: 'RedisCacheConfiguration.defaultCacheConfig().entryTtl(Duration.ofMinutes(10)).serializeValuesWith(RedisSerializationContext.SerializationPair.fromSerializer(new GenericJackson2JsonRedisSerializer()))',
      solution: '// src/main/java/com/shop/config/RedisConfig.java\n@Configuration\n@EnableCaching\npublic class RedisConfig {\n    @Bean\n    public RedisCacheConfiguration cacheConfiguration() {\n        return RedisCacheConfiguration.defaultCacheConfig()\n            .entryTtl(Duration.ofMinutes(10))\n            .disableCachingNullValues()\n            .serializeValuesWith(RedisSerializationContext.SerializationPair\n                .fromSerializer(new GenericJackson2JsonRedisSerializer()));\n    }\n\n    @Bean\n    public RedisCacheManager cacheManager(RedisConnectionFactory connectionFactory) {\n        Map<String, RedisCacheConfiguration> configs = new HashMap<>();\n        configs.put("products", RedisCacheConfiguration.defaultCacheConfig()\n            .entryTtl(Duration.ofMinutes(10)));\n        configs.put("categories", RedisCacheConfiguration.defaultCacheConfig()\n            .entryTtl(Duration.ofHours(1)));\n        return RedisCacheManager.builder(connectionFactory)\n            .cacheDefaults(cacheConfiguration())\n            .withInitialCacheConfigurations(configs)\n            .build();\n    }\n}\n\n\n// src/main/java/com/shop/service/ProductService.java (обновлённый)\n@Service @RequiredArgsConstructor\n@Slf4j\npublic class ProductService {\n\n    @Cacheable(value = "products", key = "#categoryId + \'_\' + #search + \'_\' + #pageable.pageNumber")\n    public Page<Product> getProducts(Long categoryId, String search, Pageable pageable) {\n        log.info("Cache MISS: loading products from DB (category={}, search={})", categoryId, search);\n        // ... логика получения из БД\n    }\n\n    @CacheEvict(value = "products", allEntries = true)\n    @Transactional\n    public Product create(ProductDTO dto) {\n        log.info("Cache EVICT: invalidating products cache after create");\n        // ... логика создания\n    }\n\n    @CacheEvict(value = "products", allEntries = true)\n    @Transactional\n    public void delete(Long id) {\n        productRepository.deleteById(id);\n    }\n\n    @Cacheable(value = "product", key = "#id")\n    public Product getByIdOrThrow(Long id) {\n        return productRepository.findById(id)\n            .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Товар не найден"));\n    }\n\n    @CacheEvict(value = {"products", "product"}, allEntries = true)\n    @Transactional\n    public Product update(Long id, ProductDTO dto) {\n        Product product = getByIdOrThrow(id);\n        // ... обновление полей\n        return productRepository.save(product);\n    }\n}',
      explanation: '@Cacheable проверяет Redis перед выполнением метода — если ключ найден, метод не вызывается. @CacheEvict удаляет записи из кеша после мутирующих операций. allEntries=true при CacheEvict удаляет весь кеш "products" — проще чем точечная инвалидация по всем параметрам. TTL для категорий (1 час) больше чем для товаров (10 мин) — категории меняются реже.'
    },
    {
      id: 309,
      title: 'Шаг 9: Загрузка изображений',
      type: 'practice',
      difficulty: 'medium',
      description: 'Добавьте возможность загрузки изображений товаров. Реализуйте эндпоинт загрузки файлов на Spring Boot и компонент выбора изображения в React.',
      requirements: [
        'POST /api/upload/image: принимает MultipartFile, сохраняет в uploads/ папку',
        'Настроить spring.servlet.multipart.max-file-size=5MB',
        'Валидация: только image/jpeg и image/png',
        'Возвращать URL изображения: /uploads/{filename}',
        'Настроить WebMvcConfigurer для раздачи статики из uploads/',
        'React: компонент ImageUpload с превью выбранного файла',
        'Использовать FormData для multipart запроса'
      ],
      expectedOutput: 'Можно выбрать JPG/PNG файл в форме, увидеть превью, загрузить на сервер. URL изображения автоматически подставляется в поле imageUrl товара. Файл доступен по /uploads/filename.jpg.',
      hint: 'Для раздачи статики: registry.addResourceHandler("/uploads/**").addResourceLocations("file:uploads/"). Уникальное имя файла: UUID.randomUUID() + "." + extension. React превью: URL.createObjectURL(file)',
      solution: '// src/main/java/com/shop/controller/UploadController.java\n@RestController\n@RequestMapping("/api/upload")\n@RequiredArgsConstructor\npublic class UploadController {\n    private static final List<String> ALLOWED_TYPES = List.of("image/jpeg", "image/png", "image/webp");\n    private static final String UPLOAD_DIR = "uploads/";\n\n    @PostMapping("/image")\n    @PreAuthorize("hasRole(\'ADMIN\')")\n    public Map<String, String> uploadImage(@RequestParam("file") MultipartFile file) throws IOException {\n        if (!ALLOWED_TYPES.contains(file.getContentType())) {\n            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Разрешены только JPEG, PNG, WebP");\n        }\n        if (file.getSize() > 5 * 1024 * 1024) {\n            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "Файл слишком большой (макс. 5MB)");\n        }\n        String ext = Objects.requireNonNull(file.getOriginalFilename())\n            .substring(file.getOriginalFilename().lastIndexOf("."));\n        String filename = UUID.randomUUID() + ext;\n        Path uploadPath = Path.of(UPLOAD_DIR);\n        Files.createDirectories(uploadPath);\n        Files.copy(file.getInputStream(), uploadPath.resolve(filename));\n        return Map.of("url", "/uploads/" + filename);\n    }\n}\n\n\n// src/main/java/com/shop/config/WebConfig.java\n@Configuration\npublic class WebConfig implements WebMvcConfigurer {\n    @Override\n    public void addResourceHandlers(ResourceHandlerRegistry registry) {\n        registry.addResourceHandler("/uploads/**")\n            .addResourceLocations("file:uploads/");\n    }\n}\n\n\n// application.properties (добавить)\nspring.servlet.multipart.max-file-size=5MB\nspring.servlet.multipart.max-request-size=10MB\n\n\n// src/components/ImageUpload.jsx\nimport { useState, useRef } from "react";\nimport api from "../api/axios";\nimport styles from "./ImageUpload.module.css";\n\nexport default function ImageUpload({ onUpload }) {\n  const [preview, setPreview] = useState(null);\n  const [uploading, setUploading] = useState(false);\n  const inputRef = useRef();\n\n  const handleFile = async (e) => {\n    const file = e.target.files[0];\n    if (!file) return;\n    setPreview(URL.createObjectURL(file));\n    setUploading(true);\n    try {\n      const formData = new FormData();\n      formData.append("file", file);\n      const res = await api.post("/upload/image", formData, {\n        headers: { "Content-Type": "multipart/form-data" },\n      });\n      onUpload(res.data.url);\n    } catch (err) {\n      alert(err.response?.data?.message || "Ошибка загрузки");\n    } finally {\n      setUploading(false);\n    }\n  };\n\n  return (\n    <div className={styles.container}>\n      {preview && <img src={preview} alt="Превью" className={styles.preview} />}\n      <button type="button" onClick={() => inputRef.current.click()} disabled={uploading}>\n        {uploading ? "Загружаем..." : "Выбрать изображение"}\n      </button>\n      <input ref={inputRef} type="file" accept="image/*" onChange={handleFile}\n        style={{ display: "none" }} />\n    </div>\n  );\n}',
      explanation: 'UUID для имён файлов предотвращает коллизии и скрывает оригинальные имена. URL.createObjectURL создаёт временный URL для превью без загрузки — быстро и не нагружает сервер. Files.createDirectories создаёт папку если её нет. В production изображения хранят в S3/MinIO, а не на диске сервера.'
    },
    {
      id: 310,
      title: 'Шаг 10: Поиск и фильтрация',
      type: 'practice',
      difficulty: 'medium',
      description: 'Добавьте расширенную фильтрацию товаров: по ценовому диапазону, диапазону наличия, сортировка по цене и названию. Используйте Spring Data Specifications.',
      requirements: [
        'ProductSpecification: criteria для фильтрации (category, minPrice, maxPrice, inStock, search)',
        'ProductController: принимать параметры minPrice, maxPrice, inStock, sortBy, order',
        'React: боковая панель с фильтрами цены (range inputs)',
        'Чекбокс "Только в наличии"',
        'Выпадающий список сортировки: по цене (возр/убыв), по названию',
        'Кнопка "Сбросить фильтры"',
        'Фильтры синхронизируются с URL параметрами'
      ],
      expectedOutput: 'Фильтр по цене 500-2000 ₽ показывает только товары в этом диапазоне. Чекбокс "В наличии" скрывает товары с stock=0. Сортировка по цене работает корректно.',
      hint: 'JPA Specifications: Specification<Product> priceSpec = (root, query, cb) -> cb.between(root.get("price"), minPrice, maxPrice). Комбинирование: Specification.where(spec1).and(spec2)',
      solution: '// src/main/java/com/shop/repository/ProductSpecification.java\npublic class ProductSpecification {\n\n    public static Specification<Product> hasCategory(Long categoryId) {\n        return (root, query, cb) ->\n            categoryId == null ? null : cb.equal(root.get("category").get("id"), categoryId);\n    }\n\n    public static Specification<Product> hasNameLike(String search) {\n        return (root, query, cb) ->\n            search == null ? null :\n            cb.like(cb.lower(root.get("name")), "%" + search.toLowerCase() + "%");\n    }\n\n    public static Specification<Product> priceBetween(BigDecimal min, BigDecimal max) {\n        return (root, query, cb) -> {\n            if (min != null && max != null) return cb.between(root.get("price"), min, max);\n            if (min != null) return cb.greaterThanOrEqualTo(root.get("price"), min);\n            if (max != null) return cb.lessThanOrEqualTo(root.get("price"), max);\n            return null;\n        };\n    }\n\n    public static Specification<Product> inStock() {\n        return (root, query, cb) -> cb.greaterThan(root.get("stock"), 0);\n    }\n}\n\n\n// ProductController (обновлённый метод)\n@GetMapping\npublic Page<Product> getProducts(\n        @RequestParam(required = false) Long categoryId,\n        @RequestParam(required = false) String search,\n        @RequestParam(required = false) BigDecimal minPrice,\n        @RequestParam(required = false) BigDecimal maxPrice,\n        @RequestParam(defaultValue = "false") boolean inStockOnly,\n        @RequestParam(defaultValue = "id") String sortBy,\n        @RequestParam(defaultValue = "asc") String order,\n        @RequestParam(defaultValue = "0") int page,\n        @RequestParam(defaultValue = "12") int size) {\n    Sort sort = order.equals("desc") ? Sort.by(sortBy).descending() : Sort.by(sortBy).ascending();\n    Pageable pageable = PageRequest.of(page, size, sort);\n    Specification<Product> spec = Specification\n        .where(hasCategory(categoryId))\n        .and(hasNameLike(search))\n        .and(priceBetween(minPrice, maxPrice));\n    if (inStockOnly) spec = spec.and(inStock());\n    return productRepository.findAll(spec, pageable);\n}\n\n\n// src/components/FilterPanel.jsx\nimport { useState } from "react";\nimport { useSearchParams } from "react-router-dom";\nimport styles from "./FilterPanel.module.css";\n\nexport default function FilterPanel() {\n  const [searchParams, setSearchParams] = useSearchParams();\n  const [minPrice, setMinPrice] = useState(searchParams.get("minPrice") || "");\n  const [maxPrice, setMaxPrice] = useState(searchParams.get("maxPrice") || "");\n  const [inStock, setInStock] = useState(searchParams.get("inStockOnly") === "true");\n  const [sortBy, setSortBy] = useState(searchParams.get("sortBy") || "id");\n\n  const applyFilters = () => {\n    const params = {};\n    if (minPrice) params.minPrice = minPrice;\n    if (maxPrice) params.maxPrice = maxPrice;\n    if (inStock) params.inStockOnly = "true";\n    if (sortBy !== "id") params.sortBy = sortBy;\n    setSearchParams(params);\n  };\n\n  const resetFilters = () => {\n    setMinPrice(""); setMaxPrice(""); setInStock(false); setSortBy("id");\n    setSearchParams({});\n  };\n\n  return (\n    <aside className={styles.panel}>\n      <h3>Фильтры</h3>\n      <div className={styles.priceRange}>\n        <label>Цена от:</label>\n        <input type="number" value={minPrice} onChange={(e) => setMinPrice(e.target.value)}\n          placeholder="0" min="0" />\n        <label>до:</label>\n        <input type="number" value={maxPrice} onChange={(e) => setMaxPrice(e.target.value)}\n          placeholder="99999" min="0" />\n      </div>\n      <label className={styles.checkbox}>\n        <input type="checkbox" checked={inStock} onChange={(e) => setInStock(e.target.checked)} />\n        Только в наличии\n      </label>\n      <select value={sortBy} onChange={(e) => setSortBy(e.target.value)}>\n        <option value="id">По умолчанию</option>\n        <option value="price">Цена (возр.)</option>\n        <option value="price,desc">Цена (убыв.)</option>\n        <option value="name">По названию</option>\n      </select>\n      <button onClick={applyFilters}>Применить</button>\n      <button onClick={resetFilters}>Сбросить</button>\n    </aside>\n  );\n}',
      explanation: 'JPA Specifications реализуют паттерн Specification — каждый критерий изолирован, комбинируются через .and()/.or(). Null-safe: если параметр null, Specification возвращает null и Spring Data игнорирует этот критерий. Синхронизация с URL (useSearchParams) — пользователь может поделиться ссылкой с применёнными фильтрами.'
    },
    {
      id: 311,
      title: 'Шаг 11: Swagger документация',
      type: 'practice',
      difficulty: 'easy',
      description: 'Добавьте интерактивную API документацию через Springdoc OpenAPI. Аннотируйте контроллеры и DTO для генерации полной документации.',
      requirements: [
        'Добавить зависимость springdoc-openapi-starter-webmvc-ui',
        'Настроить OpenAPI конфигурацию: title, version, description',
        'Добавить JWT Bearer аутентификацию в Swagger UI',
        '@Operation(summary="...") для каждого эндпоинта',
        '@Parameter для параметров запросов',
        '@Schema для DTO полей',
        'Группировка эндпоинтов по тегам: @Tag(name="Products")'
      ],
      expectedOutput: 'http://localhost:8080/swagger-ui.html открывает интерактивную документацию. Кнопка "Authorize" позволяет ввести JWT токен. Можно выполнять запросы прямо из документации.',
      hint: 'pom.xml: <dependency><groupId>org.springdoc</groupId><artifactId>springdoc-openapi-starter-webmvc-ui</artifactId><version>2.3.0</version></dependency>. OpenAPI Bean с securityScheme для JWT Bearer.',
      solution: '// pom.xml (добавить)\n<dependency>\n    <groupId>org.springdoc</groupId>\n    <artifactId>springdoc-openapi-starter-webmvc-ui</artifactId>\n    <version>2.3.0</version>\n</dependency>\n\n\n// src/main/java/com/shop/config/OpenApiConfig.java\n@Configuration\npublic class OpenApiConfig {\n    @Bean\n    public OpenAPI openAPI() {\n        return new OpenAPI()\n            .info(new Info()\n                .title("E-Commerce API")\n                .version("1.0.0")\n                .description("REST API для интернет-магазина на Spring Boot"))\n            .addSecurityItem(new SecurityRequirement().addList("Bearer Authentication"))\n            .components(new Components()\n                .addSecuritySchemes("Bearer Authentication",\n                    new SecurityScheme()\n                        .type(SecurityScheme.Type.HTTP)\n                        .scheme("bearer")\n                        .bearerFormat("JWT")));\n    }\n}\n\n\n// application.properties (добавить)\nspringdoc.swagger-ui.path=/swagger-ui.html\nspringdoc.api-docs.path=/api-docs\n\n\n// SecurityConfig: добавить в whitelist\n.requestMatchers("/swagger-ui/**", "/api-docs/**").permitAll()\n\n\n// ProductController (с аннотациями)\n@Tag(name = "Товары", description = "Управление каталогом товаров")\n@RestController\n@RequestMapping("/api/products")\npublic class ProductController {\n\n    @Operation(summary = "Получить список товаров",\n        description = "Возвращает страницу товаров с фильтрацией и сортировкой")\n    @ApiResponse(responseCode = "200", description = "Список товаров")\n    @GetMapping\n    public Page<Product> getProducts(\n            @Parameter(description = "ID категории для фильтрации")\n            @RequestParam(required = false) Long categoryId,\n            @Parameter(description = "Поисковый запрос")\n            @RequestParam(required = false) String search,\n            @Parameter(description = "Номер страницы (от 0)")\n            @RequestParam(defaultValue = "0") int page) {\n        // ...\n    }\n\n    @Operation(summary = "Создать товар", security = @SecurityRequirement(name = "Bearer Authentication"))\n    @ApiResponse(responseCode = "201", description = "Товар создан")\n    @ApiResponse(responseCode = "403", description = "Доступ запрещён (требуется роль ADMIN)")\n    @PostMapping\n    @PreAuthorize("hasRole(\'ADMIN\')")\n    @ResponseStatus(HttpStatus.CREATED)\n    public Product createProduct(@Valid @RequestBody ProductDTO dto) {\n        // ...\n    }\n}\n\n\n// ProductDTO (с аннотациями)\npublic class ProductDTO {\n    @Schema(description = "Название товара", example = "Ноутбук Dell XPS 15")\n    @NotBlank(message = "Название не может быть пустым")\n    private String name;\n\n    @Schema(description = "Цена товара в рублях", example = "89999.00")\n    @NotNull @Positive\n    private BigDecimal price;\n\n    @Schema(description = "Количество на складе", example = "10")\n    @NotNull @Min(0)\n    private Integer stock;\n}',
      explanation: 'Springdoc автоматически генерирует OpenAPI спецификацию из Spring MVC аннотаций — минимум дополнительного кода. SecurityScheme с Bearer JWT позволяет тестировать защищённые эндпоинты прямо в Swagger UI. @Schema примеры показывают разработчикам API что передавать — самодокументирующийся API.'
    },
    {
      id: 312,
      title: 'Шаг 12: Docker + docker-compose',
      type: 'practice',
      difficulty: 'hard',
      description: 'Контейнеризируйте всё приложение: Spring Boot, React, PostgreSQL, Redis. Используйте multi-stage build для Spring Boot с Maven.',
      requirements: [
        'backend/Dockerfile: multi-stage (maven:3.9 для сборки, eclipse-temurin:17-jre для запуска)',
        'frontend/Dockerfile: multi-stage (node:18 + nginx)',
        'docker-compose.yml: 5 сервисов — postgres, redis, spring-backend, react-frontend, nginx',
        'Healthchecks для postgres и redis',
        'spring-backend depends_on postgres и redis (с condition: service_healthy)',
        'Переменные окружения через .env файл',
        'Volumes для postgres данных и uploads'
      ],
      expectedOutput: 'docker-compose up --build запускает все 5 сервисов. http://localhost открывает магазин. http://localhost/api/products возвращает товары. Redis и PostgreSQL данные сохраняются между перезапусками.',
      hint: 'Maven multi-stage: FROM maven:3.9-eclipse-temurin-17 AS build; WORKDIR /app; COPY pom.xml .; RUN mvn dependency:go-offline; COPY src ./src; RUN mvn package -DskipTests. Затем: FROM eclipse-temurin:17-jre; COPY --from=build /app/target/*.jar app.jar',
      solution: '# backend/Dockerfile\nFROM maven:3.9-eclipse-temurin-17 AS build\nWORKDIR /app\nCOPY pom.xml .\nRUN mvn dependency:go-offline -q\nCOPY src ./src\nRUN mvn package -DskipTests -q\n\nFROM eclipse-temurin:17-jre-alpine\nWORKDIR /app\nCOPY --from=build /app/target/*.jar app.jar\nEXPOSE 8080\nENTRYPOINT ["java", "-jar", "app.jar"]\n\n\n# frontend/Dockerfile (аналогично модулю 1)\nFROM node:18-alpine AS builder\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci --silent\nCOPY . .\nRUN npm run build\n\nFROM nginx:alpine\nCOPY --from=builder /app/dist /usr/share/nginx/html\nCOPY nginx.conf /etc/nginx/conf.d/default.conf\nEXPOSE 80\n\n\n# docker-compose.yml\nversion: "3.9"\n\nservices:\n  postgres:\n    image: postgres:15-alpine\n    environment:\n      POSTGRES_USER: ${DB_USER:-shopuser}\n      POSTGRES_PASSWORD: ${DB_PASSWORD:-shoppassword}\n      POSTGRES_DB: ${DB_NAME:-shopdb}\n    volumes:\n      - postgres_data:/var/lib/postgresql/data\n    healthcheck:\n      test: ["CMD-SHELL", "pg_isready -U ${DB_USER:-shopuser}"]\n      interval: 5s\n      timeout: 5s\n      retries: 10\n\n  redis:\n    image: redis:7-alpine\n    command: redis-server --maxmemory 256mb --maxmemory-policy allkeys-lru\n    healthcheck:\n      test: ["CMD", "redis-cli", "ping"]\n      interval: 5s\n      timeout: 3s\n      retries: 5\n\n  backend:\n    build: ./backend\n    environment:\n      SPRING_DATASOURCE_URL: jdbc:postgresql://postgres:5432/${DB_NAME:-shopdb}\n      SPRING_DATASOURCE_USERNAME: ${DB_USER:-shopuser}\n      SPRING_DATASOURCE_PASSWORD: ${DB_PASSWORD:-shoppassword}\n      SPRING_DATA_REDIS_HOST: redis\n      APP_JWT_SECRET: ${JWT_SECRET:-changeMeInProduction1234567890}\n    volumes:\n      - uploads_data:/app/uploads\n    depends_on:\n      postgres:\n        condition: service_healthy\n      redis:\n        condition: service_healthy\n\n  frontend:\n    build: ./frontend\n    depends_on:\n      - backend\n\n  nginx:\n    image: nginx:alpine\n    ports:\n      - "80:80"\n    volumes:\n      - ./nginx/nginx.conf:/etc/nginx/conf.d/default.conf\n    depends_on:\n      - backend\n      - frontend\n\nvolumes:\n  postgres_data:\n  uploads_data:',
      explanation: 'Maven dependency:go-offline кеширует зависимости в отдельном слое — если pom.xml не изменился, Docker использует кешированный слой и не скачивает зависимости повторно. eclipse-temurin:17-jre-alpine — минимальный JRE образ (не JDK) для production, ~150MB против ~400MB для JDK. Redis maxmemory-policy allkeys-lru автоматически вытесняет старые ключи при заполнении памяти.'
    }
  ]
};
